import{_ as e,c as t,o as r,ag as i}from"./chunks/framework.S-Qvb3wi.js";const u=JSON.parse('{"title":"$DGAI 的核心功能：四维引擎","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/Core-Functions.md","filePath":"zh-TW/Core-Functions.md"}'),o={name:"zh-TW/Core-Functions.md"};function l(n,a,s,d,h,c){return r(),t("div",null,a[0]||(a[0]=[i('<h1 id="dgai-的核心功能-四维引擎" tabindex="-1">$DGAI 的核心功能：四维引擎 <a class="header-anchor" href="#dgai-的核心功能-四维引擎" aria-label="Permalink to &quot;$DGAI 的核心功能：四维引擎&quot;">​</a></h1><p>$DGAI 作為網絡原生通證，承擔質押、支付、激勵與治理四大核心功能，構建生態正向循環，驅動 DGrid AI 生態系統中的每個關鍵交互。</p><h2 id="質押與准入" tabindex="-1">質押與准入 <a class="header-anchor" href="#質押與准入" aria-label="Permalink to &quot;質押與准入&quot;">​</a></h2><p>節點和 AI 服務提供者需質押 $DGAI，方可獲取網絡流量、建立信譽體系，並保障網絡安全。質押要求根據節點類型分級（節點性能），質押的代幣作為對違規行為的抵押品（例如提交虛假推理結果、停機時間超過 72 小時）。惡意節點將面臨質押 $DGAI 的 5–20% 的罰沒或臨時禁用，這些措施將通過智能合約自動執行。</p><h2 id="推理任務支付" tabindex="-1">推理任務支付 <a class="header-anchor" href="#推理任務支付" aria-label="Permalink to &quot;推理任務支付&quot;">​</a></h2><p>用戶通過 DGrid 節點使用 $DGAI 支付以訪問大型語言模型（LLM）推理與 Agent 服務。費用基於以下因素動態計算：</p><ul><li><strong>計算單元（CU）</strong>：衡量推理復雜度的標準化指標（與模型大小、輸入令牌數量及執行時間掛鉤）。</li><li><strong>延遲</strong>：根據任務速度進行調整（更快執行可獲得獎勵，延遲則會受到輕微處罰）。</li></ul><p>支付通過區塊鏈部署的智能合約——賬單合約（Bill Contract）自動處理，該合約從用戶賬戶扣除 $DGAI 並向節點運營商、服務提供者等分配資金，確保交易的透明性和不可篡改性。</p><h2 id="節點運營商獎勵" tabindex="-1">節點運營商獎勵 <a class="header-anchor" href="#節點運營商獎勵" aria-label="Permalink to &quot;節點運營商獎勵&quot;">​</a></h2><p>網絡依據服務質量、使用量和用戶評價，將 $DGAI 獎勵給優質節點與 AI 服務提供者，激發貢獻熱情。根據推理任務貢獻（例如處理的 CU 數量、低延遲和運行時間）賺取 $DGAI。獎勵與性能成正比，托管大型模型（130 億參數以上）或處理高優先級請求的節點將獲得更高獎勵。獎勵每周通過賬單合約分發，詳細記錄存檔至 AI DA 以確保可審計性。</p><h2 id="網絡治理" tabindex="-1">網絡治理 <a class="header-anchor" href="#網絡治理" aria-label="Permalink to &quot;網絡治理&quot;">​</a></h2><p>$DGAI 是治理通證，持幣者有權投票決定網絡發展的關鍵事項，確保決策與活躍網絡參與者的利益保持一致，提案包括：</p><ul><li>調整費用結構（例如基礎 CU 定價、延遲罰金）。</li><li>將新的大型語言模型（LLM）加入白名單以獲得網絡支持。</li><li>升級核心協議（例如 DGridRPC）或結算規則。</li><li>分配國庫資金以促進生態系統增長（例如開發者補助金、安全審計）。</li></ul><p>投票權與質押的 $DGAI 成正比，確保決策與活躍網絡參與者的利益保持一致。</p>',14)]))}const A=e(o,[["render",l]]);export{u as __pageData,A as default};
